code = """import json

# List all available variables
all_vars = list(locals().keys())
nasdaq_var_name = None
trade_tables_var_name = None

# Find the variables we need
for var in all_vars:
    if 'query_db:24' in var:
        nasdaq_var_name = var
    elif 'query_db:26' in var:
        trade_tables_var_name = var

if nasdaq_var_name and trade_tables_var_name:
    nasdaq_data = locals()[nasdaq_var_name]
    trade_data_path = locals()[trade_tables_var_name]
    
    # Extract NASDAQ symbols
    nasdaq_symbols = [item['Symbol'] for item in nasdaq_data]
    
    # Read the trade tables data from file
    with open(trade_data_path, 'r') as f:
        trade_tables_data = json.load(f)
    
    trade_tables = [item['table_name'] for item in trade_tables_data]
    
    # Find intersection (symbols that exist in both)
    tradeable_symbols = list(set(nasdaq_symbols) & set(trade_tables))
    
    result = {
        'tradeable_symbols': tradeable_symbols,
        'count': len(tradeable_symbols)
    }
    
    print('__RESULT__:')
    print(json.dumps(result))
else:
    print('__RESULT__:')
    print(json.dumps({'error': 'Variables not found'}))"""

